// User model
class User {
  final String id;
  final String email;
  final String displayName;
  final String? avatarUrl;
  final Map<String, dynamic>? metadata;

  const User({
    required this.id,
    required this.email,
    required this.displayName,
    this.avatarUrl,
    this.metadata,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'email': email,
        'displayName': displayName,
        'avatarUrl': avatarUrl,
        'metadata': metadata,
      };

  factory User.fromJson(Map<String, dynamic> json) => User(
        id: json['id'] as String,
        email: json['email'] as String,
        displayName: json['displayName'] as String,
        avatarUrl: json['avatarUrl'] as String?,
        metadata: json['metadata'] as Map<String, dynamic>?,
      );

  @override
  bool operator ==(Object other) =>
      identical(this, other) || other is User && id == other.id;

  @override
  int get hashCode => id.hashCode;
}

// Auth tokens model
class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;
  final String tokenType;

  const AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
    this.tokenType = 'Bearer',
  });

  bool get isExpired => DateTime.now().isAfter(expiresAt);

  bool get isNearExpiry =>
      DateTime.now().isAfter(expiresAt.subtract(const Duration(minutes: 5)));

  Map<String, dynamic> toJson() => {
        'accessToken': accessToken,
        'refreshToken': refreshToken,
        'expiresAt': expiresAt.toIso8601String(),
        'tokenType': tokenType,
      };

  factory AuthTokens.fromJson(Map<String, dynamic> json) => AuthTokens(
        accessToken: json['accessToken'] as String,
        refreshToken: json['refreshToken'] as String,
        expiresAt: DateTime.parse(json['expiresAt'] as String),
        tokenType: json['tokenType'] as String? ?? 'Bearer',
      );
}

// Auth state
enum AuthStatus { unknown, authenticated, unauthenticated, loading }

class AuthState {
  final AuthStatus status;
  final User? user;
  final AuthTokens? tokens;
  final String? errorMessage;

  const AuthState({
    this.status = AuthStatus.unknown,
    this.user,
    this.tokens,
    this.errorMessage,
  });

  bool get isAuthenticated => status == AuthStatus.authenticated;

  AuthState copyWith({
    AuthStatus? status,
    User? user,
    AuthTokens? tokens,
    String? errorMessage,
  }) =>
      AuthState(
        status: status ?? this.status,
        user: user ?? this.user,
        tokens: tokens ?? this.tokens,
        errorMessage: errorMessage ?? this.errorMessage,
      );
}

// Secure storage keys with obfuscated names
class _StorageKeys {
  static const String _prefix = '_auth_mgr_';
  static const String accessToken = '${_prefix}at';
  static const String refreshToken = '${_prefix}rt';
  static const String tokenExpiry = '${_prefix}te';
  static const String tokenType = '${_prefix}tt';
  static const String userData = '${_prefix}ud';
  static const String sessionChecksum = '${_prefix}sc';
  static const String lastActivity = '${_prefix}la';
  static const String sessionVersion = '${_prefix}sv';

  static const int currentVersion = 1;
}

// Auth result from API calls
class AuthResult {
  final bool success;
  final User? user;
  final AuthTokens? tokens;
  final String? errorMessage;

  const AuthResult({
    required this.success,
    this.user,
    this.tokens,
    this.errorMessage,
  });
}

// Abstract API service for dependency injection
abstract class AuthApiService {
  Future<AuthResult> login(String email, String password);
  Future<AuthResult> refreshToken(String refreshToken);
  Future<bool> logout(String accessToken);
  Future<AuthResult> register(String email, String password, String displayName);
}

// Authentication Manager
class AuthenticationManager extends ChangeNotifier {
  final AuthApiService _apiService;
  SharedPreferences? _prefs;
  AuthState _state = const AuthState();
  Timer? _tokenRefreshTimer;
  Timer? _sessionTimeoutTimer;
  final Duration _sessionTimeout;
  final Duration _tokenRefreshBuffer;

  AuthState get state => _state;
  bool get isAuthenticated => _state.isAuthenticated;
  User? get currentUser => _state.user;
  AuthTokens? get tokens => _state.tokens;

  AuthenticationManager({
    required AuthApiService apiService,
    Duration sessionTimeout = const Duration(days: 30),
    Duration tokenRefreshBuffer = const Duration(minutes: 5),
  })  : _apiService = apiService,
        _sessionTimeout = sessionTimeout,
        _tokenRefreshBuffer = tokenRefreshBuffer;

  // Initialize and check for existing session
  Future<void> initialize() async {
    _updateState(_state.copyWith(status: AuthStatus.loading));

    try {
      _prefs = await SharedPreferences.getInstance();

      // Check session version compatibility
      final storedVersion = _prefs!.getInt(_StorageKeys.sessionVersion) ?? 0;
      if (storedVersion != _StorageKeys.currentVersion) {
        await _clearAllStoredData();
        _updateState(const AuthState(status: AuthStatus.unauthenticated));
        return;
      }

      // Check session timeout
      final lastActivityStr = _prefs!.getString(_StorageKeys.lastActivity);
      if (lastActivityStr != null) {
        final lastActivity = DateTime.tryParse(lastActivityStr);
        if (lastActivity != null &&
            DateTime.now().difference(lastActivity) > _sessionTimeout) {
          await _clearAllStoredData();
          _updateState(const AuthState(status: AuthStatus.unauthenticated));
          return;
        }
      }

      // Try to restore session
      final restored = await _restoreSession();
      if (restored) {
        _startTokenRefreshTimer();
        _startSessionTimeoutTimer();
        _updateLastActivity();
      } else {
        _updateState(const AuthState(status: AuthStatus.unauthenticated));
      }
    } catch (e) {
      debugPrint('AuthManager initialization error: $e');
      await _clearAllStoredData();
      _updateState(const AuthState(status: AuthStatus.unauthenticated));
    }
  }

  // Login
  Future<bool> login(String email, String password) async {
    if (email.isEmpty || password.isEmpty) {
      _updateState(_state.copyWith(
        status: AuthStatus.unauthenticated,
        errorMessage: 'Email and password are required',
      ));
      return false;
    }

    _updateState(_state.copyWith(status: AuthStatus.loading));

    try {
      final result = await _apiService.login(email, password);

      if (result.success && result.user != null && result.tokens != null) {
        await _persistSession(result.user!, result.tokens!);
        _updateState(AuthState(
          status: AuthStatus.authenticated,
          user: result.user,
          tokens: result.tokens,
        ));
        _startTokenRefreshTimer();
        _startSessionTimeoutTimer();
        return true;
      } else {
        _updateState(AuthState(
          status: AuthStatus.unauthenticated,
          errorMessage: result.errorMessage ?? 'Login failed',
        ));
        return false;
      }
    } catch (e) {
      _updateState(AuthState(
        status: AuthStatus.unauthenticated,
        errorMessage: 'An unexpected error occurred',
      ));
      return false;
    }
  }

  // Register
  Future<bool> register(
      String email, String password, String displayName) async {
    if (email.isEmpty || password.isEmpty || displayName.isEmpty) {
      _updateState(_state.copyWith(
        status: AuthStatus.unauthenticated,
        errorMessage: 'All fields are required',
      ));
      return false;
    }

    _updateState(_state.copyWith(status: AuthStatus.loading));

    try {
      final result =
          await _apiService.register(email, password, displayName);

      if (result.success && result.user != null && result.tokens != null) {
        await _persistSession(result.user!, result.tokens!);
        _updateState(AuthState(
          status: AuthStatus.authenticated,
          user: result.user,
          tokens: result.tokens,
        ));
        _startTokenRefreshTimer();
        _startSessionTimeoutTimer();
        return true;
      } else {
        _updateState(AuthState(
          status: AuthStatus.unauthenticated,
          errorMessage: result.errorMessage ?? 'Registration failed',
        ));
        return false;
      }
    } catch (e) {
      _updateState(AuthState(
        status: AuthStatus.unauthenticated,
        errorMessage: 'An unexpected error occurred',
      ));
      return false;
    }
  }

  // Logout
  Future<void> logout() async {
    try {
      if (_state.tokens != null) {
        await _apiService.logout(_state.tokens!.accessToken);
      }
    } catch (e) {
      debugPrint('Logout API call failed: $e');
    } finally {
      _cancelTimers();
      await _clearAllStoredData();
      _updateState(const AuthState(status: AuthStatus.unauthenticated));
    }
  }

  // Force logout (e.g., on 401 response)
  Future<void> forceLogout({String? reason}) async {
    _cancelTimers();
    await _clearAllStoredData();
    _updateState(AuthState(
      status: AuthStatus.unauthenticated,
      errorMessage: reason ?? 'Session expired. Please log in again.',
    ));
  }

  // Refresh tokens
  Future<bool> refreshTokens() async {
    if (_state.tokens == null) return false;

    try {
      final result =
          await _apiService.refreshToken(_state.tokens!.refreshToken);

      if (result.success && result.tokens != null) {
        final user = result.user ?? _state.user;
        if (user != null) {
          await _persistSession(user, result.tokens!);
          _updateState(AuthState(
            status: AuthStatus.authenticated,
            user: user,
            tokens: result.tokens,
          ));
          _startTokenRefreshTimer();
          return true;
        }
      }

      // Refresh failed - force logout
      await forceLogout(reason: 'Session expired. Please log in again.');
      return false;
    } catch (e) {
      debugPrint('Token refresh error: $e');
      await forceLogout(reason: 'Session expired. Please log in again.');
      return false;
    }
  }

  // Update user data
  Future<void> updateUser(User user) async {
    if (!isAuthenticated) return;

    await _persistUserData(user);
    _updateState(_state.copyWith(user: user));
  }

  // Record user activity (call from UI interactions)
  void recordActivity() {
    if (isAuthenticated) {
      _updateLastActivity();
      _resetSessionTimeoutTimer();
    }
  }

  // Get authorization header value
  String? getAuthorizationHeader() {
    if (_state.tokens == null) return null;
    return '${_state.tokens!.tokenType} ${_state.tokens!.accessToken}';
  }

  // --- Private methods ---

  void _updateState(AuthState newState) {
    _state = newState;
    notifyListeners();
  }

  Future<bool> _restoreSession() async {
    final prefs = _prefs;
    if (prefs == null) return false;

    try {
      final accessToken = prefs.getString(_StorageKeys.accessToken);
      final refreshToken = prefs.getString(_StorageKeys.refreshToken);
      final tokenExpiryStr = prefs.getString(_StorageKeys.tokenExpiry);
      final tokenType = prefs.getString(_StorageKeys.tokenType);
      final userDataStr = prefs.getString(_StorageKeys.userData);
      final storedChecksum = prefs.getString(_StorageKeys.sessionChecksum);

      if (accessToken == null ||
          refreshToken == null ||
          tokenExpiryStr == null ||
          userDataStr == null ||
          storedChecksum == null) {
        return false;
      }

      // Verify data integrity
      final computedChecksum =
          _computeChecksum(accessToken, refreshToken, userDataStr);
      if (computedChecksum != storedChecksum) {
        debugPrint('Session data integrity check failed');
        await _clearAllStoredData();
        return false;
      }

      final tokenExpiry = DateTime.tryParse(tokenExpiryStr);
      if (tokenExpiry == null) return false;

      final tokens = AuthTokens(
        accessToken: accessToken,
        refreshToken: refreshToken,
        expiresAt: tokenExpiry,
        tokenType: tokenType ?? 'Bearer',
      );

      final userDataJson = jsonDecode(userDataStr) as Map<String, dynamic>;
      final user = User.fromJson(userDataJson);

      // If access token is expired, try to refresh
      if (tokens.isExpired) {
        final result = await _apiService.refreshToken(refreshToken);
        if (result.success && result.tokens != null) {
          final refreshedUser = result.user ?? user;
          await _persistSession(refreshedUser, result.tokens!);
          _updateState(AuthState(
            status: AuthStatus.authenticated,
            user: refreshedUser,
            tokens: result.tokens,
          ));
          return true;
        }
        return false;
      }

      _updateState(AuthState(
        status: AuthStatus.authenticated,
        user: user,
        tokens: tokens,
      ));
      return true;
    } catch (e) {
      debugPrint('Session restore error: $e');
      return false;
    }
  }

  Future<void> _persistSession(User user, AuthTokens tokens) async {
    final prefs = _prefs;
    if (prefs == null) return;

    final userDataStr = jsonEncode(user.toJson());
    final checksum =
        _computeChecksum(tokens.accessToken, tokens.refreshToken, userDataStr);

    await Future.wait([
      prefs.setString(_StorageKeys.accessToken, tokens.accessToken),
      prefs.setString(_StorageKeys.refreshToken, tokens.refreshToken),
      prefs.setString(
          _StorageKeys.tokenExpiry, tokens.expiresAt.toIso8601String()),
      prefs.setString(_StorageKeys.tokenType, tokens.tokenType),
      prefs.setString(_StorageKeys.userData, userDataStr),
      prefs.setString(_StorageKeys.sessionChecksum, checksum),
      prefs.setString(
          _StorageKeys.lastActivity, DateTime.now().toIso8601String()),
      prefs.setInt(
          _StorageKeys.sessionVersion, _StorageKeys.currentVersion),
    ]);
  }

  Future<void> _persistUserData(User user) async {
    final prefs = _prefs;
    if (prefs == null || _state.tokens == null) return;

    final userDataStr = jsonEncode(user.toJson());
    final checksum = _computeChecksum(
      _state.tokens!.accessToken,
      _state.tokens!.refreshToken,
      userDataStr,
    );

    await Future.wait([
      prefs.setString(_StorageKeys.userData, userDataStr),
      prefs.setString(_StorageKeys.sessionChecksum, checksum),
    ]);
  }

  Future<void> _clearAllStoredData() async {
    final prefs = _prefs;
    if (prefs == null) return;

    await Future.wait([
      prefs.remove(_StorageKeys.accessToken),
      prefs.remove(_StorageKeys.refreshToken),
      prefs.remove(_StorageKeys.tokenExpiry),
      prefs.remove(_StorageKeys.tokenType),
      prefs.remove(_StorageKeys.userData),
      prefs.remove(_StorageKeys.sessionChecksum),
      prefs.remove(_StorageKeys.lastActivity),
      prefs.remove(_StorageKeys.sessionVersion),
    ]);
  }

  void _updateLastActivity() {
    _prefs?.setString(
        _StorageKeys.lastActivity, DateTime.now().toIso8601String());
  }

  String _computeChecksum(
      String accessToken, String refreshToken, String userData) {
    final data = '$accessToken|$refreshToken|$userData';
    final bytes = utf8.encode(data);
    final digest = sha256.convert(bytes);
    return digest.toString();
  }

  void _startTokenRefreshTimer() {
    _tokenRefreshTimer?.cancel();

    if (_state.tokens == null) return;

    final timeUntilRefresh =
        _state.tokens!.expiresAt.difference(DateTime.now()) -
            _tokenRefreshBuffer;

    if (timeUntilRefresh.isNegative) {
      // Token is already near expiry or expired, refresh immediately
      refreshTokens();
      return;
    }

    _tokenRefreshTimer = Timer(timeUntilRefresh, () {
      refreshTokens();
    });
  }

  void _startSessionTimeoutTimer() {
    _sessionTimeoutTimer?.cancel();
    _sessionTimeoutTimer = Timer(_sessionTimeout, () {
      forceLogout(reason: 'Session timed out due to inactivity.');
    });
  }

  void _resetSessionTimeoutTimer() {
    _startSessionTimeoutTimer();
  }

  void _cancelTimers() {
    _tokenRefreshTimer?.cancel();
    _tokenRefreshTimer = null;
    _sessionTimeoutTimer?.cancel();
    _sessionTimeoutTimer = null;
  }

  @override
  void dispose() {
    _cancelTimers();
    super.dispose();
  }
}

